import*as Schema from"../schema.js";import*as Instance from"../instance.js";const id="https://json-schema.org/keyword/required",compile=e=>Schema.value(e),interpret=(e,t)=>!Instance.typeOf(t,"object")||e.every(e=>Object.hasOwn(Instance.value(t),e));export default{id:id,compile:compile,interpret:interpret};